     1→/**
     2→ * Project Context Detection Utility
     3→ *
     4→ * Detects whether the current working directory is within a project,
     5→ * enabling project-specific memory routing for the Hybrid with Virtual
     6→ * Access Layer architecture.
     7→ *
     8→ * Implements Path 3: Virtual First - lowest risk approach.
     9→ *
    10→ * @module hooks/lib/project-context
    11→ */
    12→
    13→import { homedir } from 'os';
    14→import { join, basename, dirname } from 'path';
    15→import { existsSync, readFileSync, writeFileSync, mkdirSync, renameSync } from 'fs';
    16→import { getPaiDir, paiPath } from './paths';
    17→
    18→/**
    19→ * Project information interface
    20→ *
    21→ * Represents a detected project with its memory configuration.
    22→ */
    23→export interface ProjectInfo {
    24→  /** Project name (directory basename) */
    25→  name: string;
    26→  /** Absolute path to project root */
    27→  rootPath: string;
    28→  /** Path where project memories should be stored */
    29→  memoryPath: string;
    30→  /** Whether this is the PAI project itself */
    31→  isPAIProject: boolean;
    32→  /** Detection method used */
    33→  detectionMethod: 'projects-dir' | 'marker-file' | 'cwd';
    34→}
    35→
    36→/**
    37→ * Project index entry
    38→ *
    39→ * Stores metadata about a project in the central index.
    40→ */
    41→export interface ProjectIndexEntry {
    42→  /** Project name */
    43→  name: string;
    44→  /** Absolute path to project root */
    45→  path: string;
    46→  /** Work session IDs associated with this project */
    47→  workIds: string[];
    48→  /** Last activity timestamp */
    49→  lastActive: string;
    50→}
    51→
    52→/**
    53→ * Project index structure
    54→ *
    55→ * Top-level structure of the projects.json index file.
    56→ */
    57→export interface ProjectIndex {
    58→  /** Map of project names to their index entries */
    59→  projects: Record<string, ProjectIndexEntry>;
    60→  /** Index last updated timestamp */
    61→  updatedAt: string;
    62→}
    63→
    64→/**
    65→ * Maximum iterations for directory traversal
    66→ *
    67→ * Prevents infinite loops when walking up the directory tree
    68→ * looking for marker files.
    69→ */
    70→const MAX_TRAVERSAL_ITERATIONS = 50;
    71→
    72→/**
    73→ * Marker file for project root detection
    74→ *
    75→ * When this file exists in a directory, that directory is treated
    76→ * as a project root regardless of location.
    77→ */
    78→const PAI_ROOT_MARKER = '.pai-root';
    79→
    80→/**
    81→ * Project index directory
    82→ */
    83→const PROJECT_INDEX_DIR = paiPath('MEMORY', 'STATE', '.project-index');
    84→
    85→/**
    86→ * Project index file
    87→ */
    88→const PROJECT_INDEX_FILE = join(PROJECT_INDEX_DIR, 'projects.json');
    89→
    90→/**
    91→ * Error types for project detection
    92→ */
    93→export enum ProjectDetectionError {
    94→  /** Filesystem operation failed */
    95→  FILESYSTEM_ERROR = 'FILESYSTEM_ERROR',
    96→  /** Maximum traversal depth exceeded */
    97→  MAX_DEPTH_EXCEEDED = 'MAX_DEPTH_EXCEEDED',
    98→  /** Path resolution failed */
    99→  PATH_RESOLUTION_ERROR = 'PATH_RESOLUTION_ERROR',
   100→}
   101→
   102→/**
   103→ * Detect project context from current working directory
   104→ *
   105→ * Implements a three-tier detection strategy:
   106→ * 1. Check if CWD is in ~/Projects/* (simple detection)
   107→ * 2. Fall back to .pai-root marker file detection (walk up tree)
   108→ * 3. Return null for central mode (when in PAI itself or no project detected)
   109→ *
   110→ * @returns ProjectInfo if detected, null for central mode
   111→ *
   112→ * @example
   113→ * ```typescript
   114→ * const project = detectProject();
   115→ * if (project) {
   116→ *   console.log(`Working in project: ${project.name}`);
   117→ *   console.log(`Memories stored in: ${project.memoryPath}`);
   118→ * } else {
   119→ *   console.log('Using central memory mode');
   120→ * }
   121→ * ```
   122→ */
   123→export function detectProject(): ProjectInfo | null {
   124→  try {
   125→    const cwd = process.cwd();
   126→
   127→    // Safety check: ensure we have a valid CWD
   128→    if (!cwd || typeof cwd !== 'string') {
   129→      console.error('[project-context] Invalid CWD detected');
   130→      return null;
   131→    }
   132→
   133→    // Check if we're IN the PAI project itself
   134→    const paiDir = getPaiDir();
   135→    if (cwd.startsWith(paiDir) || cwd.includes('.claude')) {
   136→      // We're working on PAI itself - use central mode
   137→      return null;
   138→    }
   139→
   140→    // Strategy 1: Check if CWD is in ~/Projects/*
   141→    const projectsRoot = join(homedir(), 'Projects');
   142→    if (cwd.startsWith(projectsRoot)) {
   143→      const projectName = basename(cwd);
   144→      return {
   145→        name: projectName,
   146→        rootPath: cwd,
   147→        memoryPath: join(cwd, '.pai-memory'),
   148→        isPAIProject: false,
   149→        detectionMethod: 'projects-dir',
   150→      };
   151→    }
   152→
   153→    // Strategy 2: Walk up tree looking for .pai-root marker
   154→    let current = cwd;
   155→    let iterations = 0;
   156→
   157→    while (iterations < MAX_TRAVERSAL_ITERATIONS) {
   158→      const markerPath = join(current, PAI_ROOT_MARKER);
   159→
   160→      if (existsSync(markerPath)) {
   161→        const projectName = basename(current);
   162→        return {
   163→          name: projectName,
   164→          rootPath: current,
   165→          memoryPath: join(current, '.pai-memory'),
   166→          isPAIProject: false,
   167→          detectionMethod: 'marker-file',
   168→        };
   169→      }
   170→
   171→      // Move up one directory
   172→      const parent = dirname(current);
   173→
   174→      // Stop if we've reached the home directory or root
   175→      if (parent === current || parent === homedir() || parent === dirname(homedir())) {
   176→        break;
   177→      }
   178→
   179→      current = parent;
   180→      iterations++;
   181→    }
   182→
   183→    // Check if we exceeded max iterations
   184→    if (iterations >= MAX_TRAVERSAL_ITERATIONS) {
   185→      console.error(`[project-context] Max traversal depth (${MAX_TRAVERSAL_ITERATIONS}) exceeded`);
   186→      return null;
   187→    }
   188→
   189→    // Strategy 3: Check CWD itself as a potential project root
   190→    // This handles cases where user is in a project outside ~/Projects
   191→    // and hasn't created a marker file yet
   192→    const hasGit = existsSync(join(cwd, '.git'));
   193→    const hasPackageJson = existsSync(join(cwd, 'package.json'));
   194→    const hasCargoToml = existsSync(join(cwd, 'Cargo.toml'));
   195→
   196→    if (hasGit || hasPackageJson || hasCargoToml) {
   197→      const projectName = basename(cwd);
   198→      return {
   199→        name: projectName,
   200→        rootPath: cwd,
   201→        memoryPath: join(cwd, '.pai-memory'),
   202→        isPAIProject: false,
   203→        detectionMethod: 'cwd',
   204→      };
   205→    }
   206→
   207→    // No project detected - use central mode
   208→    return null;
   209→
   210→  } catch (error) {
   211→    // Log error but don't throw - fall back to central mode
   212→    console.error('[project-context] Detection failed:', error instanceof Error ? error.message : String(error));
   213→    return null;
   214→  }
   215→}
   216→
   217→/**
   218→ * Get memory directory for current context
   219→ *
   220→ * Returns the appropriate memory directory based on project detection.
   221→ * Uses project-local memory if a project is detected, otherwise central.
   222→ *
   223→ * @param subdirectory Optional subdirectory (e.g., 'WORK', 'LEARNING')
   224→ * @returns Absolute path to memory directory
   225→ */
   226→export function getMemoryDir(subdirectory?: string): string {
   227→  const project = detectProject();
   228→
   229→  if (project) {
   230→    // Project mode
   231→    return subdirectory
   232→      ? join(project.memoryPath, subdirectory)
   233→      : project.memoryPath;
   234→  }
   235→
   236→  // Central mode
   237→  return subdirectory
   238→    ? paiPath('MEMORY', subdirectory)
   239→    : paiPath('MEMORY');
   240→}
   241→
   242→/**
   243→ * Ensure project index directory exists
   244→ */
   245→function ensureProjectIndexDir(): void {
   246→  try {
   247→    if (!existsSync(PROJECT_INDEX_DIR)) {
   248→      mkdirSync(PROJECT_INDEX_DIR, { recursive: true });
   249→    }
   250→  } catch (error) {
   251→    console.error('[project-context] Failed to create project index directory:', error);
   252→    // Non-fatal - continue without index
   253→  }
   254→}
   255→
   256→/**
   257→ * Read project index from disk
   258→ *
   259→ * @returns Project index data, or empty index if file doesn't exist
   260→ */
   261→export function getProjectIndex(): ProjectIndex {
   262→  try {
   263→    ensureProjectIndexDir();
   264→
   265→    if (existsSync(PROJECT_INDEX_FILE)) {
   266→      const content = readFileSync(PROJECT_INDEX_FILE, 'utf-8');
   267→      return JSON.parse(content) as ProjectIndex;
   268→    }
   269→
   270→    // Return empty index
   271→    return {
   272→      projects: {},
   273→      updatedAt: new Date().toISOString(),
   274→    };
   275→  } catch (error) {
   276→    console.error('[project-context] Failed to read project index:', error);
   277→    // Return empty index on error
   278→    return {
   279→      projects: {},
   280→      updatedAt: new Date().toISOString(),
   281→    };
   282→  }
   283→}
   284→
   285→/**
   286→ * Write project index to disk atomically
   287→ *
   288→ * Uses temp-file + rename pattern for atomic writes.
   289→ *
   290→ * @param index Project index data to write
   291→ */
   292→function writeProjectIndex(index: ProjectIndex): void {
   293→  try {
   294→    ensureProjectIndexDir();
   295→
   296→    // Update timestamp
   297→    index.updatedAt = new Date().toISOString();
   298→
   299→    // Write to temp file first
   300→    const tempFile = `${PROJECT_INDEX_FILE}.tmp`;
   301→    writeFileSync(tempFile, JSON.stringify(index, null, 2), 'utf-8');
   302→
   303→    // Atomic rename
   304→    renameSync(tempFile, PROJECT_INDEX_FILE);
   305→
   306→  } catch (error) {
   307→    console.error('[project-context] Failed to write project index:', error);
   308→    // Non-fatal - log but don't throw
   309→  }
   310→}
   311→
   312→/**
   313→ * Update project index with a new work session
   314→ *
   315→ * Adds the work session ID to the appropriate project's entry
   316→ * in the index, creating a new entry if needed.
   317→ *
   318→ * @param projectName Project name
   319→ * @param workId Work session ID
   320→ * @param workPath Absolute path to work directory
   321→ */
   322→export function updateProjectIndex(
   323→  projectName: string,
   324→  workId: string,
   325→  workPath: string
   326→): void {
   327→  try {
   328→    const index = getProjectIndex();
   329→
   330→    if (!index.projects[projectName]) {
   331→      // Detect project to get path
   332→      const project = detectProject();
   333→      const projectPath = project?.rootPath || workPath;
   334→
   335→      index.projects[projectName] = {
   336→        name: projectName,
   337→        path: projectPath,
   338→        workIds: [],
   339→        lastActive: new Date().toISOString(),
   340→      };
   341→    }
   342→
   343→    // Add work ID if not already present
   344→    const entry = index.projects[projectName];
   345→    if (!entry.workIds.includes(workId)) {
   346→      entry.workIds.push(workId);
   347→    }
   348→
   349→    // Update last active time
   350→    entry.lastActive = new Date().toISOString();
   351→
   352→    writeProjectIndex(index);
   353→
   354→  } catch (error) {
   355→    console.error('[project-context] Failed to update project index:', error);
   356→    // Non-fatal - don't block work creation
   357→  }
   358→}
   359→
   360→/**
   361→ * Get all work IDs for a specific project
   362→ *
   363→ * @param projectName Project name
   364→ * @returns Array of work session IDs, empty array if project not found
   365→ */
   366→export function getProjectWorkIds(projectName: string): string[] {
   367→  try {
   368→    const index = getProjectIndex();
   369→    return index.projects[projectName]?.workIds || [];
   370→  } catch (error) {
   371→    console.error('[project-context] Failed to get project work IDs:', error);
   372→    return [];
   373→  }
   374→}
   375→
   376→/**
   377→ * Get all projects in the index
   378→ *
   379→ * @returns Array of project index entries
   380→ */
   381→export function getAllProjects(): ProjectIndexEntry[] {
   382→  try {
   383→    const index = getProjectIndex();
   384→    return Object.values(index.projects);
   385→  } catch (error) {
   386→    console.error('[project-context] Failed to get all projects:', error);
   387→    return [];
   388→  }
   389→}
   390→
   391→/**
   392→ * Create .pai-root marker file in current directory
   393→ *
   394→ * Initializes a project root marker for explicit project detection.
   395→ *
   396→ * @param directory Optional directory path (defaults to CWD)
   397→ * @returns true if marker created, false otherwise
   398→ */
   399→export function createProjectMarker(directory?: string): boolean {
   400→  try {
   401→    const targetDir = directory || process.cwd();
   402→    const markerPath = join(targetDir, PAI_ROOT_MARKER);
   403→
   404→    if (!existsSync(markerPath)) {
   405→      writeFileSync(markerPath, '# PAI Project Root\n# This file marks this directory as a project root\n', 'utf-8');
   406→      return true;
   407→    }
   408→
   409→    return false;
   410→  } catch (error) {
   411→    console.error('[project-context] Failed to create project marker:', error);
   412→    return false;
   413→  }
   414→}
   415→
   416→/**
   417→ * Check if currently in a project
   418→ *
   419→ * Convenience function that returns true if a project is detected.
   420→ *
   421→ * @returns true if in a project, false otherwise
   422→ */
   423→export function isInProject(): boolean {
   424→  return detectProject() !== null;
   425→}
   426→
   427→/**
   428→ * Get current project name
   429→ *
   430→ * Convenience function that returns the current project name,
   431→ * or null if not in a project.
   432→ *
   433→ * @returns Project name or null
   434→ */
   435→export function getCurrentProjectName(): string | null {
   436→  const project = detectProject();
   437→  return project?.name || null;
   438→}
