     1→#!/usr/bin/env bun
     2→/**
     3→ * ProjectMemories - Query interface for project-specific memories
     4→ *
     5→ * This tool provides a CLI interface for querying memories by project context.
     6→ * It implements the "Virtual View" architecture from the memory system investigation,
     7→ * allowing unified access to both central and project-local memories.
     8→ *
     9→ * Commands:
    10→ *   --current          Get memories for current project (based on CWD)
    11→ *   --project <name>   Get memories for specific project by name
    12→ *   --list             List all projects with memories
    13→ *   --unified          Show unified index (central + project)
    14→ *   --type <type>      Filter by memory type (WORK|LEARNING|RESEARCH)
    15→ *   --json             Output as JSON instead of markdown
    16→ *   --help             Show help
    17→ *
    18→ * Examples:
    19→ *   bun ProjectMemories.ts --current
    20→ *   bun ProjectMemories.ts --project my-app
    21→ *   bun ProjectMemories.ts --list
    22→ *   bun ProjectMemories.ts --unified --type WORK
    23→ *
    24→ * Architecture:
    25→ * - Uses project index at MEMORY/STATE/.project-index/projects.json
    26→ * - Falls back to scanning if index doesn't exist
    27→ * - Detects project from CWD using marker files
    28→ *
    29→ * Version: 1.0.0
    30→ * ISC: #5 - Create query interface for project memories
    31→ */
    32→
    33→import { parseArgs } from "util";
    34→import * as fs from "fs";
    35→import * as path from "path";
    36→
    37→// ============================================================================
    38→// Configuration
    39→// ============================================================================
    40→
    41→const HOME_DIR = process.env.HOME || process.env.USERPROFILE || require("os").homedir();
    42→const CLAUDE_DIR = path.join(HOME_DIR, ".claude");
    43→const MEMORY_DIR = path.join(CLAUDE_DIR, "MEMORY");
    44→const PROJECT_INDEX_DIR = path.join(MEMORY_DIR, "STATE", ".project-index");
    45→const PROJECT_INDEX_FILE = path.join(PROJECT_INDEX_DIR, "projects.json");
    46→
    47→// ============================================================================
    48→// Types
    49→// ============================================================================
    50→
    51→interface ProjectInfo {
    52→  name: string;
    53→  path: string;
    54→  workIds: string[];
    55→  lastActive: string;
    56→  memoryPath?: string; // Optional: if project has local .pai/MEMORY
    57→}
    58→
    59→interface ProjectIndex {
    60→  projects: Record<string, ProjectInfo>;
    61→  updatedAt: string;
    62→  version: string;
    63→}
    64→
    65→interface MemoryFile {
    66→  type: "WORK" | "LEARNING" | "RESEARCH";
    67→  path: string;
    68→  date: string;
    69→  description?: string;
    70→  project: string;
    71→}
    72→
    73→interface MemoryQueryResult {
    74→  project: string;
    75→  projectPath: string;
    76→  memories: MemoryFile[];
    77→  totalByType: Record<string, number>;
    78→}
    79→
    80→// ============================================================================
    81→// Project Detection
    82→// ============================================================================
    83→
    84→/**
    85→ * Detect project from current working directory
    86→ * Uses multiple strategies: CWD pattern, marker files, git detection
    87→ */
    88→function detectProject(): { name: string; path: string } | null {
    89→  const cwd = process.cwd();
    90→
    91→  // Strategy 1: Check if we're in ~/Projects/* pattern
    92→  const projectsRoot = path.join(HOME_DIR, "Projects");
    93→  if (cwd.startsWith(projectsRoot)) {
    94→    const parts = cwd.substring(projectsRoot.length).split(path.sep).filter(Boolean);
    95→    if (parts.length > 0) {
    96→      return {
    97→        name: parts[0],
    98→        path: path.join(projectsRoot, parts[0]),
    99→      };
   100→    }
   101→  }
   102→
   103→  // Strategy 2: Look for .pai-root marker (walk up tree)
   104→  let current = cwd;
   105→  let iterations = 0;
   106→  const maxIterations = 50; // Prevent infinite loops
   107→
   108→  while (current !== HOME_DIR && current !== path.dirname(current) && iterations < maxIterations) {
   109→    const markerPath = path.join(current, ".pai-root");
   110→    if (fs.existsSync(markerPath)) {
   111→      return {
   112→        name: path.basename(current),
   113→        path: current,
   114→      };
   115→    }
   116→    current = path.dirname(current);
   117→    iterations++;
   118→  }
   119→
   120→  // Strategy 3: Check for git repository (common project marker)
   121→  try {
   122→    const gitPath = path.join(cwd, ".git");
   123→    if (fs.existsSync(gitPath)) {
   124→      return {
   125→        name: path.basename(cwd),
   126→        path: cwd,
   127→      };
   128→    }
   129→  } catch {
   130→    // Git check failed, continue
   131→  }
   132→
   133→  return null; // No project detected
   134→}
   135→
   136→/**
   137→ * Detect if project has local .pai/MEMORY directory
   138→ */
   139→function detectLocalMemoryPath(projectPath: string): string | null {
   140→  const candidates = [
   141→    path.join(projectPath, ".pai", "MEMORY"),
   142→    path.join(projectPath, ".pai-memory"),
   143→    path.join(projectPath, ".claude", "MEMORY"),
   144→  ];
   145→
   146→  for (const candidate of candidates) {
   147→    if (fs.existsSync(candidate)) {
   148→      return candidate;
   149→    }
   150→  }
   151→
   152→  return null;
   153→}
