   155→// ============================================================================
   156→// Project Index Management
   157→// ============================================================================
   158→
   159→/**
   160→ * Load project index from disk, creating empty one if missing
   161→ */
   162→function loadProjectIndex(): ProjectIndex {
   163→  try {
   164→    if (fs.existsSync(PROJECT_INDEX_FILE)) {
   165→      const content = fs.readFileSync(PROJECT_INDEX_FILE, "utf-8");
   166→      return JSON.parse(content);
   167→    }
   168→  } catch (error) {
   169→    console.warn(`# Warning: Could not load project index: ${error}`);
   170→  }
   171→
   172→  // Return empty index
   173→  return {
   174→    projects: {},
   175→    updatedAt: new Date().toISOString(),
   176→    version: "1.0.0",
   177→  };
   178→}
   179→
   180→/**
   181→ * Save project index to disk
   182→ */
   183→function saveProjectIndex(index: ProjectIndex): void {
   184→  try {
   185→    if (!fs.existsSync(PROJECT_INDEX_DIR)) {
   186→      fs.mkdirSync(PROJECT_INDEX_DIR, { recursive: true });
   187→    }
   188→    index.updatedAt = new Date().toISOString();
   189→    fs.writeFileSync(PROJECT_INDEX_FILE, JSON.stringify(index, null, 2));
   190→  } catch (error) {
   191→    console.warn(`# Warning: Could not save project index: ${error}`);
   192→  }
   193→}
   194→
   195→/**
   196→ * Rebuild project index by scanning actual directories
   197→ */
   198→function rebuildProjectIndex(): ProjectIndex {
   199→  const index: ProjectIndex = {
   200→    projects: {},
   201→    updatedAt: new Date().toISOString(),
   202→    version: "1.0.0",
   203→  };
   204→
   205→  // Scan central WORK directory
   206→  const centralWorkDir = path.join(MEMORY_DIR, "WORK");
   207→  if (fs.existsSync(centralWorkDir)) {
   208→    const workDirs = fs.readdirSync(centralWorkDir, { withFileTypes: true })
   209→      .filter(d => d.isDirectory())
   210→      .map(d => d.name);
   211→
   212→    for (const workId of workDirs) {
   213→      const metaPath = path.join(centralWorkDir, workId, "META.yaml");
   214→      if (fs.existsSync(metaPath)) {
   215→        const meta = parseMetaFile(metaPath);
   216→        const projectName = meta.project || "central";
   217→
   218→        if (!index.projects[projectName]) {
   219→          index.projects[projectName] = {
   220→            name: projectName,
   221→            path: meta.projectPath || CLAUDE_DIR,
   222→            workIds: [],
   223→            lastActive: meta.date || new Date().toISOString(),
   224→          };
   225→        }
   226→
   227→        index.projects[projectName].workIds.push(workId);
   228→      }
   229→    }
   230→  }
   231→
   232→  // Scan for local project memories
   233→  // This would scan ~/Projects/* for .pai/MEMORY directories
   234→  const projectsRoot = path.join(HOME_DIR, "Projects");
   235→  if (fs.existsSync(projectsRoot)) {
   236→    const projectDirs = fs.readdirSync(projectsRoot, { withFileTypes: true })
   237→      .filter(d => d.isDirectory())
   238→      .map(d => d.name);
   239→
   240→    for (const projectName of projectDirs) {
   241→      const projectPath = path.join(projectsRoot, projectName);
   242→      const localMemory = detectLocalMemoryPath(projectPath);
   243→
   244→      if (localMemory && !index.projects[projectName]) {
   245→        index.projects[projectName] = {
   246→          name: projectName,
   247→          path: projectPath,
   248→          workIds: [],
   249→          lastActive: new Date().toISOString(),
   250→          memoryPath: localMemory,
   251→        };
   252→      } else if (localMemory && index.projects[projectName]) {
   253→        index.projects[projectName].memoryPath = localMemory;
   254→      }
   255→    }
   256→  }
   257→
   258→  return index;
   259→}
   260→
   261→/**
   262→ * Parse META.yaml file for project metadata
   263→ */
   264→function parseMetaFile(metaPath: string): { project?: string; projectPath?: string; date?: string } {
   265→  try {
   266→    const content = fs.readFileSync(metaPath, "utf-8");
   267→    const lines = content.split("\n");
   268→
   269→    const result: Record<string, string> = {};
   270→    for (const line of lines) {
   271→      const match = line.match(/^(\w+):\s*(.+)$/);
   272→      if (match) {
   273→        result[match[1]] = match[2];
   274→      }
   275→    }
   276→
   277→    return {
   278→      project: result.project,
   279→      projectPath: result.project_path || result.projectPath,
   280→      date: result.date || result.created,
   281→    };
   282→  } catch {
   283→    return {};
   284→  }
   285→}
